import { useEffect, useMemo, useRef, useState } from 'react';
import { Doughnut, Bar } from 'react-chartjs-2';
import { Chart as ChartJS, ArcElement, BarElement, CategoryScale, LinearScale, Tooltip, Legend } from 'chart.js';
import { QRCodeCanvas } from 'qrcode.react';
import { Html5Qrcode } from 'html5-qrcode';
import { jsPDF } from 'jspdf';
import autoTable from 'jspdf-autotable';
import {
  AlertTriangle, ArrowDownToLine, ArrowRightLeft, BarChart3, Bell, Box, Check, CheckCircle2, ChevronRight, ClipboardCheck,
  Clock3, FileText, Gauge, LayoutDashboard, LogOut, MapPin, Menu, PackageCheck, Plus, QrCode, ScanLine, Search, Settings,
  ShieldCheck, Sparkles, Users, Wrench, X,
} from 'lucide-react';
import { api } from './api.js';

ChartJS.register(ArcElement, BarElement, CategoryScale, LinearScale, Tooltip, Legend);

const demoCredentials = { email: 'admin@nexus.edu', password: 'NexusDemo!2026' };
const nav = [
  ['dashboard', LayoutDashboard, 'Command Center'], ['assets', Box, 'Asset Registry'], ['scanner', ScanLine, 'Scan & Move'],
  ['maintenance', Wrench, 'Maintenance'], ['reports', FileText, 'Reports'],
];
const statusColor = {
  available: 'bg-emerald-50 text-emerald-700 ring-emerald-600/15', assigned: 'bg-blue-50 text-blue-700 ring-blue-600/15',
  maintenance: 'bg-amber-50 text-amber-700 ring-amber-600/15', retired: 'bg-slate-100 text-slate-600 ring-slate-500/15', lost: 'bg-rose-50 text-rose-700 ring-rose-600/15',
  open: 'bg-amber-50 text-amber-700 ring-amber-600/15', in_progress: 'bg-blue-50 text-blue-700 ring-blue-600/15', resolved: 'bg-emerald-50 text-emerald-700 ring-emerald-600/15',
};
const riskColor = { healthy: 'text-emerald-600 bg-emerald-50', watch: 'text-amber-600 bg-amber-50', high: 'text-orange-600 bg-orange-50', critical: 'text-rose-600 bg-rose-50' };
const idOf = (item) => item?._id || item?.id;
const date = (value, empty = '—') => value ? new Intl.DateTimeFormat('en-IN', { day: '2-digit', month: 'short', year: 'numeric' }).format(new Date(value)) : empty;
const relative = (value) => {
  const days = Math.round((new Date(value) - new Date()) / 86400000);
  if (days === 0) return 'Today'; if (days === 1) return 'Tomorrow'; if (days === -1) return '1 day overdue'; return days < 0 ? `${Math.abs(days)} days overdue` : `in ${days} days`;
};
const titleCase = (value = '') => value.replaceAll('_', ' ').replace(/\b\w/g, (letter) => letter.toUpperCase());

function useToast() {
  const [toast, setToast] = useState(null);
  const show = (message, kind = 'success') => { setToast({ message, kind }); window.setTimeout(() => setToast(null), 3500); };
  return { toast, show };
}

function Badge({ children, value, className = '' }) { return <span className={`pill ring-1 ${statusColor[value] || 'bg-slate-100 text-slate-600 ring-slate-500/15'} ${className}`}>{children || titleCase(value)}</span>; }
function Empty({ icon: Icon = Box, title, copy, action }) { return <div className="flex min-h-56 flex-col items-center justify-center px-6 text-center"><div className="mb-4 rounded-2xl bg-brand-50 p-3 text-brand-600"><Icon size={24} /></div><h3 className="font-extrabold text-ink">{title}</h3><p className="mt-1 max-w-xs text-sm text-slate-500">{copy}</p>{action && <div className="mt-5">{action}</div>}</div>; }
function Spinner() { return <div className="flex min-h-48 items-center justify-center"><div className="h-7 w-7 animate-spin rounded-full border-2 border-brand-100 border-t-brand-600" /></div>; }
function Modal({ title, children, onClose, wide = false }) { return <div className="fixed inset-0 z-50 flex items-end bg-slate-950/40 p-0 backdrop-blur-sm sm:items-center sm:justify-center sm:p-6" role="dialog" aria-modal="true"><div className={`max-h-[92vh] w-full overflow-y-auto rounded-t-3xl bg-white shadow-2xl sm:rounded-3xl ${wide ? 'sm:max-w-4xl' : 'sm:max-w-lg'}`}><div className="sticky top-0 z-10 flex items-center justify-between border-b bg-white/95 px-5 py-4 backdrop-blur sm:px-7"><h2 className="text-lg font-extrabold text-ink">{title}</h2><button onClick={onClose} className="rounded-xl p-2 text-slate-400 hover:bg-slate-100 hover:text-slate-700" aria-label="Close"><X size={20} /></button></div><div className="p-5 sm:p-7">{children}</div></div></div>; }
function Toast({ toast }) { return toast && <div className={`fixed bottom-5 right-5 z-[70] flex max-w-sm items-center gap-3 rounded-2xl border px-4 py-3 text-sm font-bold shadow-2xl ${toast.kind === 'error' ? 'border-rose-100 bg-rose-50 text-rose-700' : 'border-emerald-100 bg-white text-slate-700'}`}>{toast.kind === 'error' ? <AlertTriangle size={18} /> : <CheckCircle2 className="text-emerald-500" size={18} />}{toast.message}</div>; }

function Login({ onLogin }) {
  const [values, setValues] = useState(demoCredentials); const [loading, setLoading] = useState(false); const [error, setError] = useState('');
  const submit = async (event) => { event.preventDefault(); setLoading(true); setError(''); try { await onLogin(values); } catch (err) { setError(err.message); } finally { setLoading(false); } };
  return <main className="min-h-screen bg-[#0d1230] p-5 text-white"><div className="absolute inset-0 overflow-hidden"><div className="absolute -left-20 top-0 h-96 w-96 rounded-full bg-brand-600/30 blur-3xl" /><div className="absolute right-0 top-1/3 h-80 w-80 rounded-full bg-cyan-400/10 blur-3xl" /></div><div className="relative mx-auto grid min-h-[calc(100vh-2.5rem)] max-w-6xl items-center gap-16 lg:grid-cols-[1.15fr_.85fr]"><section className="max-w-xl"><div className="mb-12 flex items-center gap-3"><Logo /><span className="font-extrabold tracking-tight">NEXUS <span className="font-medium text-indigo-200">ASSETS</span></span></div><p className="eyebrow text-indigo-200">Smart asset intelligence</p><h1 className="mt-4 text-4xl font-extrabold leading-[1.12] tracking-tight sm:text-6xl">Every asset, <span className="text-indigo-300">accounted for.</span></h1><p className="mt-6 max-w-lg text-base leading-7 text-slate-300">A clear, intelligent operating system for the equipment your campus depends on—built to prevent loss before it happens.</p><div className="mt-10 grid grid-cols-3 gap-3"><MiniStat icon={QrCode} text="QR enabled" /><MiniStat icon={Sparkles} text="AI signals" /><MiniStat icon={ShieldCheck} text="Audit ready" /></div></section><section className="rounded-3xl border border-white/10 bg-white p-7 text-slate-700 shadow-2xl shadow-black/20 sm:p-9"><div className="mb-7"><p className="eyebrow">Welcome back</p><h2 className="mt-2 text-2xl font-extrabold text-ink">Sign in to Nexus</h2><p className="mt-1 text-sm text-slate-500">Use the demo account to explore the system.</p></div><form onSubmit={submit} className="space-y-4"><div><label className="label">Work email</label><input className="field" type="email" value={values.email} onChange={(e) => setValues({ ...values, email: e.target.value })} /></div><div><label className="label">Password</label><input className="field" type="password" value={values.password} onChange={(e) => setValues({ ...values, password: e.target.value })} /></div>{error && <p className="rounded-xl bg-rose-50 px-3 py-2 text-sm font-semibold text-rose-600">{error}</p>}<button disabled={loading} className="btn-primary mt-2 w-full">{loading ? 'Signing in…' : 'Enter Command Center'} <ChevronRight size={17} /></button></form><div className="mt-6 rounded-2xl bg-slate-50 p-3.5 text-xs text-slate-500"><span className="font-bold text-slate-700">Demo:</span> admin@nexus.edu · NexusDemo!2026</div></section></div></main>;
}
function MiniStat({ icon: Icon, text }) { return <div className="rounded-2xl border border-white/10 bg-white/5 p-3 text-center"><Icon size={18} className="mx-auto mb-2 text-indigo-300" /><span className="text-[11px] font-bold text-slate-200">{text}</span></div>; }
function Logo() { return <div className="grid h-9 w-9 place-items-center rounded-xl bg-brand-600 text-white shadow-lg shadow-brand-600/35"><Box size={20} strokeWidth={2.5} /></div>; }

function Sidebar({ page, setPage, user, onLogout, open, setOpen }) { return <><button onClick={() => setOpen(true)} className="fixed left-4 top-4 z-30 rounded-xl border bg-white p-2 text-slate-600 shadow-card lg:hidden"><Menu size={21} /></button>{open && <button aria-label="Close menu" onClick={() => setOpen(false)} className="fixed inset-0 z-30 bg-slate-950/35 lg:hidden" />}<aside className={`fixed inset-y-0 left-0 z-40 flex w-72 flex-col border-r border-slate-200 bg-white px-4 py-5 transition-transform lg:static lg:translate-x-0 ${open ? 'translate-x-0' : '-translate-x-full'}`}><div className="flex items-center gap-3 px-3"><Logo /><div><p className="text-sm font-extrabold tracking-tight text-ink">NEXUS ASSETS</p><p className="text-[10px] font-bold tracking-wider text-brand-600">UNIVERSITY OPS</p></div><button onClick={() => setOpen(false)} className="ml-auto p-2 text-slate-400 lg:hidden"><X size={19} /></button></div><div className="mt-10 space-y-1">{nav.map(([key, Icon, label]) => <button key={key} onClick={() => { setPage(key); setOpen(false); }} className={`nav-item ${page === key ? 'nav-item-active' : ''}`}><Icon size={18} />{label}{key === 'maintenance' && <span className="ml-auto rounded-full bg-amber-100 px-2 py-0.5 text-[10px] text-amber-700">LIVE</span>}</button>)}</div><div className="mt-auto"><div className="mb-3 rounded-2xl bg-gradient-to-br from-indigo-50 to-brand-50 p-4"><div className="flex items-center gap-2 text-brand-700"><Sparkles size={16} /><span className="text-xs font-extrabold">Nexus Intelligence</span></div><p className="mt-2 text-[11px] leading-4 text-slate-500">Risk signals and timely recommendations are ready in your dashboard.</p></div><div className="flex items-center gap-3 px-3 py-3"><div className="grid h-9 w-9 place-items-center rounded-xl bg-slate-900 text-xs font-extrabold text-white">{user.name.split(' ').map((n) => n[0]).slice(0, 2)}</div><div className="min-w-0 flex-1"><p className="truncate text-xs font-extrabold text-ink">{user.name}</p><p className="text-[10px] font-bold uppercase tracking-wide text-slate-400">{titleCase(user.role)}</p></div><button onClick={onLogout} className="rounded-lg p-2 text-slate-400 hover:bg-rose-50 hover:text-rose-600" title="Sign out"><LogOut size={17} /></button></div></div></aside></>; }

function App() {
  const [session, setSession] = useState(() => { try { return JSON.parse(localStorage.getItem('nexus-session')); } catch { return null; } });
  const [page, setPage] = useState('dashboard'); const [mobileNav, setMobileNav] = useState(false); const { toast, show } = useToast();
  const login = async (values) => { const response = await api.login(values.email, values.password); const next = { ...response, savedAt: Date.now() }; localStorage.setItem('nexus-session', JSON.stringify(next)); setSession(next); };
  const logout = () => { localStorage.removeItem('nexus-session'); setSession(null); setPage('dashboard'); };
  if (!session) return <><Login onLogin={login} /><Toast toast={toast} /></>;
  return <div className="min-h-screen bg-panel lg:flex"><Sidebar page={page} setPage={setPage} user={session.user} onLogout={logout} open={mobileNav} setOpen={setMobileNav} /><main className="min-w-0 flex-1 pb-10"><Topbar page={page} user={session.user} setPage={setPage} /><div className="mx-auto max-w-[1600px] px-4 pt-4 sm:px-6 lg:px-8 lg:pt-7">{page === 'dashboard' && <Dashboard token={session.token} user={session.user} setPage={setPage} show={show} />}{page === 'assets' && <Assets token={session.token} user={session.user} show={show} />}{page === 'scanner' && <Scanner token={session.token} user={session.user} show={show} />}{page === 'maintenance' && <MaintenancePage token={session.token} user={session.user} show={show} />}{page === 'reports' && <Reports token={session.token} show={show} />}</div></main><Toast toast={toast} /></div>;
}

function Topbar({ page, user, setPage }) { const labels = { dashboard: ['Good morning', 'Here is your campus asset pulse.'], assets: ['Asset registry', 'Search, inspect, and manage every asset.'], scanner: ['Scan & move', 'Fast, auditable asset handoffs.'], maintenance: ['Maintenance desk', 'Keep critical equipment classroom-ready.'], reports: ['Reports center', 'Export an audit-ready record in seconds.'] }; const [headline, subline] = labels[page]; return <header className="sticky top-0 z-20 border-b border-slate-200/70 bg-panel/90 px-4 py-4 backdrop-blur sm:px-6 lg:px-8"><div className="mx-auto flex max-w-[1600px] items-center justify-between pl-12 lg:pl-0"><div><p className="text-lg font-extrabold tracking-tight text-ink sm:text-2xl">{headline}, {user.name.split(' ')[0]} <span className="inline-block">👋</span></p><p className="mt-0.5 hidden text-xs font-medium text-slate-500 sm:block">{subline}</p></div><div className="flex items-center gap-2"><button onClick={() => setPage('scanner')} className="btn-secondary hidden sm:inline-flex"><QrCode size={16} />Scan asset</button><button className="relative rounded-xl border border-slate-200 bg-white p-2.5 text-slate-500 hover:text-ink"><Bell size={18} /><span className="absolute right-2 top-2 h-1.5 w-1.5 rounded-full bg-rose-500 ring-2 ring-white" /></button></div></div></header>; }

function Dashboard({ token, setPage, show }) {
  const [data, setData] = useState(null); const [ai, setAi] = useState(null); const [error, setError] = useState('');
  const load = async () => { setError(''); try { const [dashboard, insights] = await Promise.all([api.dashboard(token), api.insights(token)]); setData(dashboard); setAi(insights); } catch (err) { setError(err.message); } };
  useEffect(() => { load(); }, [token]); // eslint-disable-line react-hooks/exhaustive-deps
  if (error) return <ConnectionError error={error} onRetry={load} />; if (!data) return <Spinner />;
  const { metrics, charts, alerts, recent } = data;
  const chartDefaults = { responsive: true, maintainAspectRatio: false, plugins: { legend: { display: false }, tooltip: { padding: 10, cornerRadius: 10 } } };
  return <div className="space-y-5"><section className="grid gap-3 sm:grid-cols-2 xl:grid-cols-5"><Metric label="Tracked assets" value={metrics.total} icon={Box} accent="indigo" trend="Portfolio overview" /><Metric label="Ready to deploy" value={metrics.available} icon={PackageCheck} accent="emerald" trend={`${metrics.total ? Math.round(metrics.available / metrics.total * 100) : 0}% of inventory`} /><Metric label="On loan" value={metrics.assigned} icon={ArrowRightLeft} accent="blue" trend="Active custody" /><Metric label="In maintenance" value={metrics.maintenance} icon={Wrench} accent="amber" trend="Needs technician review" /><Metric label="Overdue returns" value={metrics.overdueLoans} icon={AlertTriangle} accent="rose" trend="Requires attention" urgent={metrics.overdueLoans > 0} /></section>
  <section className="grid gap-5 xl:grid-cols-[1.45fr_.85fr]"><div className="surface p-5 sm:p-6"><div className="mb-5 flex items-start justify-between"><div><p className="eyebrow">Asset distribution</p><h2 className="mt-1 text-lg font-extrabold text-ink">What your campus holds</h2></div><button onClick={() => setPage('assets')} className="text-xs font-extrabold text-brand-600 hover:text-brand-700">View registry →</button></div><div className="h-64"><Bar data={{ labels: charts.category.map((item) => item._id), datasets: [{ data: charts.category.map((item) => item.count), backgroundColor: ['#5965f2', '#8b5cf6', '#06b6d4', '#10b981', '#f59e0b', '#f43f5e', '#64748b'], borderRadius: 8, borderSkipped: false, maxBarThickness: 38 }] }} options={{ ...chartDefaults, scales: { x: { grid: { display: false }, ticks: { font: { weight: '600' }, color: '#64748b' } }, y: { beginAtZero: true, grid: { color: '#eef2f7' }, ticks: { precision: 0, color: '#94a3b8' } } } }} /></div><div className="mt-4 grid grid-cols-3 gap-2 border-t pt-4 sm:grid-cols-6">{charts.locations.map((item) => <div key={item._id} className="min-w-0"><p className="truncate text-[10px] font-bold uppercase tracking-wide text-slate-400">{item._id}</p><p className="mt-1 text-sm font-extrabold text-ink">{item.count} <span className="text-[10px] text-slate-400">assets</span></p></div>)}</div></div>
  <AiPanel data={ai} setPage={setPage} /></section>
  <section className="grid gap-5 xl:grid-cols-3"><div className="surface p-5 sm:p-6"><div className="mb-4 flex items-center justify-between"><div><p className="eyebrow">Condition health</p><h2 className="mt-1 font-extrabold text-ink">Inventory condition</h2></div><Gauge className="text-brand-600" size={20} /></div><div className="mx-auto h-44 max-w-[240px]"><Doughnut data={{ labels: charts.conditions.map((item) => titleCase(item._id)), datasets: [{ data: charts.conditions.map((item) => item.count), backgroundColor: ['#10b981', '#5965f2', '#f59e0b', '#f43f5e'], borderWidth: 0, cutout: '74%' }] }} options={{ responsive: true, maintainAspectRatio: false, plugins: { legend: { position: 'bottom', labels: { boxWidth: 8, boxHeight: 8, usePointStyle: true, pointStyle: 'circle', padding: 12, font: { size: 10, weight: '600' } } } } }} /></div></div>
  <AlertList title="Priority queue" subtitle="Loans & maintenance requiring action" icon={Clock3} items={[...alerts.overdueLoans.map((item) => ({ title: item.asset?.name || 'Asset', meta: `${item.asset?.assetTag || ''} · ${relative(item.dueDate)}`, level: 'danger', click: () => setPage('scanner') })), ...alerts.dueMaintenance.map((item) => ({ title: item.title, meta: `${item.asset?.assetTag || 'Asset'} · ${relative(item.dueDate)}`, level: item.priority === 'critical' || item.priority === 'high' ? 'danger' : 'warn', click: () => setPage('maintenance') }))]} empty="No urgent loans or maintenance items." />
  <AlertList title="Asset watchlist" subtitle="Risk signals detected by Nexus" icon={AlertTriangle} items={alerts.riskAlerts.map((item) => ({ title: item.name, meta: `${item.assetTag} · ${item.riskScore}% risk`, level: item.riskLevel === 'critical' ? 'danger' : 'warn', click: () => setPage('assets') }))} empty="Your portfolio looks healthy." /></section>
  <section className="surface overflow-hidden"><div className="flex items-center justify-between border-b px-5 py-4 sm:px-6"><div><p className="eyebrow">System activity</p><h2 className="mt-1 font-extrabold text-ink">Recent audit trail</h2></div><button onClick={() => show('The complete audit export is available in Reports.')} className="text-xs font-extrabold text-brand-600">Export audit →</button></div><div className="divide-y">{recent.length ? recent.map((event) => <div key={idOf(event)} className="flex items-center gap-3 px-5 py-3.5 sm:px-6"><EventIcon action={event.action} /><div className="min-w-0 flex-1"><p className="truncate text-sm font-bold text-ink">{titleCase(event.action)}</p><p className="truncate text-xs text-slate-500">{event.actor?.name || event.actorName || 'System'} · {new Date(event.createdAt).toLocaleString()}</p></div><ChevronRight size={17} className="text-slate-300" /></div>) : <Empty title="No activity yet" copy="Asset actions will appear here as they happen." />}</div></section></div>;
}
function Metric({ label, value, icon: Icon, accent, trend, urgent }) { const colours = { indigo: 'bg-brand-50 text-brand-600', emerald: 'bg-emerald-50 text-emerald-600', blue: 'bg-blue-50 text-blue-600', amber: 'bg-amber-50 text-amber-600', rose: 'bg-rose-50 text-rose-600' }; return <div className="surface p-4"><div className="flex items-start justify-between"><div className={`rounded-xl p-2.5 ${colours[accent]}`}><Icon size={18} /></div>{urgent && <span className="mt-1 h-2 w-2 animate-pulse rounded-full bg-rose-500" />}</div><p className="mt-4 text-2xl font-extrabold tracking-tight text-ink">{value}</p><p className="mt-1 text-xs font-bold text-slate-600">{label}</p><p className={`mt-2 text-[10px] font-bold ${urgent ? 'text-rose-600' : 'text-slate-400'}`}>{trend}</p></div>; }
function AiPanel({ data, setPage }) { if (!data) return <div className="surface p-6"><Spinner /></div>; return <div className="overflow-hidden rounded-2xl bg-[#141a42] p-5 text-white shadow-card sm:p-6"><div className="flex items-start justify-between"><div className="flex items-center gap-2"><div className="rounded-lg bg-white/10 p-2 text-indigo-200"><Sparkles size={17} /></div><div><p className="text-sm font-extrabold">Nexus Intelligence</p><p className="text-[10px] font-semibold text-indigo-200">{data.source === 'openai' ? 'OpenAI-powered analysis' : 'Live rule-based analysis'}</p></div></div><span className="rounded-full bg-white/10 px-2 py-1 text-[9px] font-extrabold uppercase tracking-widest text-indigo-100">Live</span></div><p className="mt-5 text-sm leading-6 text-indigo-100">{data.summary}</p><div className="mt-5 space-y-2.5">{data.insights.map((item, index) => <button key={`${item.title}-${index}`} onClick={() => setPage(item.action?.toLowerCase().includes('maintenance') ? 'maintenance' : item.action?.toLowerCase().includes('loan') ? 'scanner' : 'assets')} className="group flex w-full items-start gap-3 rounded-xl bg-white/[.07] p-3 text-left transition hover:bg-white/[.12]"><span className={`mt-0.5 h-2 w-2 shrink-0 rounded-full ${item.level === 'high' ? 'bg-rose-400' : item.level === 'medium' ? 'bg-amber-300' : 'bg-emerald-400'}`} /><span className="min-w-0 flex-1"><span className="block text-xs font-extrabold text-white">{item.title}</span><span className="mt-1 block text-[11px] leading-4 text-indigo-200">{item.body}</span></span><ChevronRight size={15} className="mt-1 text-indigo-300 opacity-0 transition group-hover:opacity-100" /></button>)}</div></div>; }
function AlertList({ title, subtitle, icon: Icon, items, empty }) { return <div className="surface overflow-hidden"><div className="flex items-start gap-3 border-b p-5"><div className="rounded-xl bg-slate-100 p-2 text-slate-600"><Icon size={17} /></div><div><p className="font-extrabold text-ink">{title}</p><p className="text-[11px] text-slate-500">{subtitle}</p></div></div><div className="divide-y">{items.length ? items.slice(0, 4).map((item, index) => <button onClick={item.click} key={`${item.title}-${index}`} className="flex w-full items-center gap-3 px-5 py-3 text-left hover:bg-slate-50"><span className={`h-2 w-2 rounded-full ${item.level === 'danger' ? 'bg-rose-500' : 'bg-amber-500'}`} /><div className="min-w-0 flex-1"><p className="truncate text-xs font-extrabold text-ink">{item.title}</p><p className={`mt-0.5 text-[10px] font-bold ${item.level === 'danger' ? 'text-rose-600' : 'text-amber-600'}`}>{item.meta}</p></div><ChevronRight size={15} className="text-slate-300" /></button>) : <p className="px-5 py-10 text-center text-xs font-medium text-slate-400">{empty}</p>}</div></div>; }
function EventIcon({ action }) { const isMaintenance = action.includes('maintenance'); const isLoan = action.includes('checked') || action.includes('returned'); const Icon = isMaintenance ? Wrench : isLoan ? ArrowRightLeft : ClipboardCheck; return <div className={`rounded-lg p-2 ${isMaintenance ? 'bg-amber-50 text-amber-600' : isLoan ? 'bg-blue-50 text-blue-600' : 'bg-brand-50 text-brand-600'}`}><Icon size={15} /></div>; }
function ConnectionError({ error, onRetry }) { return <div className="surface"><Empty icon={AlertTriangle} title="We couldn't reach Nexus" copy={`${error} Start the API and seed the demo database, then try again.`} action={<button onClick={onRetry} className="btn-primary">Try again</button>} /></div>; }

function Assets({ token, user, show }) {
  const [query, setQuery] = useState({ search: '', status: '', category: '' }); const [data, setData] = useState(null); const [selected, setSelected] = useState(null); const [newOpen, setNewOpen] = useState(false); const [error, setError] = useState('');
  const canEdit = ['admin', 'asset_manager'].includes(user.role);
  const load = async () => { try { setError(''); setData(await api.assets(token, query)); } catch (err) { setError(err.message); } };
  useEffect(() => { const timer = setTimeout(load, 220); return () => clearTimeout(timer); }, [token, query.search, query.status, query.category]); // eslint-disable-line react-hooks/exhaustive-deps
  const select = async (asset) => { try { setSelected({ loading: true, asset }); const result = await api.asset(token, idOf(asset)); setSelected(result); } catch (err) { show(err.message, 'error'); setSelected(null); } };
  if (error) return <ConnectionError error={error} onRetry={load} />;
  return <div className="space-y-5"><section className="surface p-4 sm:p-5"><div className="flex flex-col gap-3 lg:flex-row lg:items-center"><div className="relative flex-1"><Search size={18} className="absolute left-3.5 top-3 text-slate-400" /><input className="field pl-10" placeholder="Search by asset tag, name, or serial number…" value={query.search} onChange={(e) => setQuery({ ...query, search: e.target.value })} /></div><select className="field w-full lg:w-40" value={query.status} onChange={(e) => setQuery({ ...query, status: e.target.value })}><option value="">All statuses</option>{['available', 'assigned', 'maintenance', 'retired', 'lost'].map((value) => <option value={value} key={value}>{titleCase(value)}</option>)}</select><select className="field w-full lg:w-44" value={query.category} onChange={(e) => setQuery({ ...query, category: e.target.value })}><option value="">All categories</option>{['Laptop', 'Projector', 'Laboratory Equipment', 'Networking', 'Camera', 'Printer', 'Furniture'].map((value) => <option value={value} key={value}>{value}</option>)}</select>{canEdit && <button onClick={() => setNewOpen(true)} className="btn-primary shrink-0"><Plus size={17} />Add asset</button>}</div></section>
  <div className="flex items-center justify-between"><p className="text-sm font-bold text-slate-500">{data ? <><span className="text-ink">{data.total}</span> assets in registry</> : 'Loading registry…'}</p><p className="hidden text-xs font-semibold text-slate-400 sm:block">QR-ready • Audit protected</p></div>
  <section className="surface overflow-hidden">{!data ? <Spinner /> : data.assets.length === 0 ? <Empty title="No matching assets" copy="Try clearing filters or add the first asset to this registry." action={canEdit && <button onClick={() => setNewOpen(true)} className="btn-primary">Add asset</button>} /> : <><div className="hidden grid-cols-[1.7fr_.9fr_.8fr_.8fr_.5fr] gap-4 border-b bg-slate-50 px-6 py-3 text-[10px] font-extrabold uppercase tracking-[.12em] text-slate-400 md:grid"><span>Asset</span><span>Location</span><span>Condition</span><span>Status</span><span>Risk</span></div><div className="divide-y">{data.assets.map((asset) => <button key={idOf(asset)} onClick={() => select(asset)} className="grid w-full gap-2 px-4 py-4 text-left transition hover:bg-brand-50/40 md:grid-cols-[1.7fr_.9fr_.8fr_.8fr_.5fr] md:items-center md:gap-4 md:px-6"><div className="flex min-w-0 items-center gap-3"><AssetGlyph category={asset.category} /><div className="min-w-0"><p className="truncate text-sm font-extrabold text-ink">{asset.name}</p><p className="mt-0.5 font-mono text-[11px] font-medium text-slate-400">{asset.assetTag} · {asset.manufacturer || 'Unspecified'}</p></div></div><p className="flex items-center gap-1 truncate text-xs font-semibold text-slate-500"><MapPin size={13} className="shrink-0 text-slate-400" />{asset.location}</p><p className="text-xs font-bold text-slate-600">{titleCase(asset.condition)}</p><div><Badge value={asset.status} /></div><div className="flex items-center gap-2"><span className={`grid h-7 w-10 place-items-center rounded-lg text-[11px] font-extrabold ${riskColor[asset.riskLevel || 'healthy']}`}>{asset.riskScore}%</span><ChevronRight size={16} className="text-slate-300 md:hidden" /></div></button>)}</div></>}</section>{selected && <AssetDetail detail={selected} token={token} user={user} onClose={() => setSelected(null)} onChanged={() => { load(); select(selected.asset || selected.asset); }} show={show} />}{newOpen && <AssetForm token={token} onClose={() => setNewOpen(false)} onCreated={() => { setNewOpen(false); load(); show('Asset added and QR identity generated.'); }} show={show} />}</div>;
}
function AssetGlyph({ category, size = 'normal' }) { const colour = { Laptop: 'bg-brand-50 text-brand-600', Projector: 'bg-violet-50 text-violet-600', 'Laboratory Equipment': 'bg-amber-50 text-amber-600', Networking: 'bg-cyan-50 text-cyan-600', Camera: 'bg-rose-50 text-rose-600', Printer: 'bg-blue-50 text-blue-600', Furniture: 'bg-emerald-50 text-emerald-600' }[category] || 'bg-slate-100 text-slate-600'; return <div className={`grid shrink-0 place-items-center rounded-xl ${size === 'large' ? 'h-12 w-12' : 'h-10 w-10'} ${colour}`}><Box size={size === 'large' ? 23 : 18} /></div>; }

function AssetDetail({ detail, token, user, onClose, onChanged, show }) {
  const [mode, setMode] = useState(null); if (detail.loading) return <Modal title="Loading asset" onClose={onClose}><Spinner /></Modal>;
  const { asset, activeAssignment, maintenance, history } = detail; const canEdit = ['admin', 'asset_manager'].includes(user.role);
  return <Modal title="Asset intelligence" onClose={onClose} wide><div className="grid gap-7 lg:grid-cols-[1fr_.85fr]"><section><div className="flex items-start gap-4"><AssetGlyph category={asset.category} size="large" /><div className="min-w-0 flex-1"><div className="flex flex-wrap items-center gap-2"><h3 className="text-xl font-extrabold text-ink">{asset.name}</h3><Badge value={asset.status} /></div><p className="mt-1 font-mono text-xs text-slate-400">{asset.assetTag} · {asset.serialNumber || 'No serial number'}</p><p className="mt-3 text-sm leading-6 text-slate-500">{asset.notes || 'No operational notes have been added for this asset.'}</p></div></div><div className="mt-6 grid grid-cols-2 gap-3 sm:grid-cols-3"><InfoCard label="Location" value={asset.location} icon={MapPin} /><InfoCard label="Condition" value={titleCase(asset.condition)} icon={Gauge} /><InfoCard label="Next service" value={date(asset.nextMaintenanceDate)} icon={Wrench} /><InfoCard label="Warranty" value={date(asset.warrantyExpiry)} icon={ShieldCheck} /><InfoCard label="Risk score" value={`${asset.riskScore}% · ${titleCase(asset.riskLevel)}`} icon={AlertTriangle} /><InfoCard label="Category" value={asset.category} icon={Box} /></div>{activeAssignment && <div className="mt-5 rounded-2xl border border-blue-100 bg-blue-50 p-4"><p className="eyebrow text-blue-600">Currently assigned</p><p className="mt-1 text-sm font-extrabold text-ink">{activeAssignment.assigneeName}</p><p className="mt-1 text-xs text-blue-700">Due {date(activeAssignment.dueDate)} · {relative(activeAssignment.dueDate)}</p>{canEdit && <button onClick={() => setMode('return')} className="btn-secondary mt-3 bg-white text-blue-700">Return asset</button>}</div>}<div className="mt-6"><div className="mb-3 flex items-center justify-between"><h4 className="font-extrabold text-ink">Lifecycle activity</h4><span className="text-xs font-bold text-slate-400">{history.length} events</span></div><div className="max-h-48 divide-y overflow-y-auto rounded-2xl border scrollbar-thin">{history.length ? history.map((event) => <div className="flex gap-3 p-3" key={idOf(event)}><EventIcon action={event.action} /><div><p className="text-xs font-bold text-ink">{titleCase(event.action)}</p><p className="mt-0.5 text-[10px] text-slate-500">{event.actor?.name || event.actorName} · {new Date(event.createdAt).toLocaleString()}</p></div></div>) : <p className="p-5 text-center text-xs text-slate-400">No lifecycle events recorded.</p>}</div></div></section><aside className="border-t pt-6 lg:border-l lg:border-t-0 lg:pl-7 lg:pt-0"><div className="flex flex-col items-center rounded-2xl border bg-slate-50 p-5"><QRCodeCanvas value={asset.qrCode} size={148} level="H" includeMargin /><p className="mt-3 font-mono text-xs font-bold text-slate-500">{asset.assetTag}</p><button onClick={() => printLabel(asset)} className="btn-secondary mt-4 w-full"><QrCode size={16} />Print QR label</button></div><div className="mt-5 space-y-2">{canEdit && asset.status === 'available' && <button onClick={() => setMode('checkout')} className="btn-primary w-full"><ArrowRightLeft size={16} />Check out asset</button>}{['admin', 'asset_manager', 'technician'].includes(user.role) && !['retired', 'lost'].includes(asset.status) && <button onClick={() => setMode('maintenance')} className="btn-secondary w-full"><Wrench size={16} />Open maintenance ticket</button>}{canEdit && <button onClick={() => setMode('edit')} className="btn-secondary w-full"><Settings size={16} />Edit asset record</button>}</div><div className="mt-6"><p className="eyebrow">Maintenance tickets</p><div className="mt-2 space-y-2">{maintenance.length ? maintenance.map((ticket) => <div className="rounded-xl border p-3" key={idOf(ticket)}><div className="flex items-center justify-between gap-2"><p className="truncate text-xs font-extrabold text-ink">{ticket.title}</p><Badge value={ticket.status} /></div><p className="mt-1 text-[11px] text-slate-500">{titleCase(ticket.priority)} priority · due {date(ticket.dueDate)}</p></div>) : <p className="rounded-xl bg-slate-50 p-3 text-xs text-slate-400">No maintenance tickets.</p>}</div></div></aside></div>{mode === 'checkout' && <CheckoutForm token={token} asset={asset} onClose={() => setMode(null)} onDone={() => { setMode(null); onChanged(); show('Asset checked out and custody audit recorded.'); }} />}{mode === 'return' && <ReturnForm token={token} assignment={activeAssignment} onClose={() => setMode(null)} onDone={() => { setMode(null); onChanged(); show('Asset returned successfully.'); }} />}{mode === 'maintenance' && <MaintenanceForm token={token} asset={asset} onClose={() => setMode(null)} onDone={() => { setMode(null); onChanged(); show('Maintenance ticket opened.'); }} />}{mode === 'edit' && <AssetForm token={token} initial={asset} onClose={() => setMode(null)} onCreated={() => { setMode(null); onChanged(); show('Asset record updated.'); }} show={show} />}</Modal>;
}
function InfoCard({ label, value, icon: Icon }) { return <div className="surface-soft p-3"><Icon size={14} className="mb-2 text-slate-400" /><p className="text-[10px] font-extrabold uppercase tracking-wide text-slate-400">{label}</p><p className="mt-1 truncate text-xs font-bold text-ink" title={value}>{value}</p></div>; }

const isoInput = (value) => value ? new Date(value).toISOString().slice(0, 10) : '';
function AssetForm({ token, initial, onClose, onCreated, show }) {
  const [values, setValues] = useState(() => ({ assetTag: initial?.assetTag || '', name: initial?.name || '', category: initial?.category || 'Laptop', manufacturer: initial?.manufacturer || '', model: initial?.model || '', serialNumber: initial?.serialNumber || '', location: initial?.location || '', department: initial?.department || 'Engineering & Sciences', condition: initial?.condition || 'good', status: initial?.status === 'assigned' ? 'available' : initial?.status || 'available', purchaseDate: isoInput(initial?.purchaseDate), purchaseCost: initial?.purchaseCost || '', warrantyExpiry: isoInput(initial?.warrantyExpiry), maintenanceIntervalDays: initial?.maintenanceIntervalDays || 180, lastMaintenanceDate: isoInput(initial?.lastMaintenanceDate), notes: initial?.notes || '' }));
  const [busy, setBusy] = useState(false); const [error, setError] = useState(''); const isEditing = Boolean(initial);
  const submit = async (event) => { event.preventDefault(); setBusy(true); setError(''); const payload = { ...values, assetTag: values.assetTag.toUpperCase(), purchaseCost: values.purchaseCost === '' ? undefined : Number(values.purchaseCost), maintenanceIntervalDays: Number(values.maintenanceIntervalDays), purchaseDate: values.purchaseDate || undefined, warrantyExpiry: values.warrantyExpiry || undefined, lastMaintenanceDate: values.lastMaintenanceDate || undefined }; try { if (isEditing) await api.updateAsset(token, idOf(initial), payload); else await api.createAsset(token, payload); onCreated(); } catch (err) { setError(err.message); } finally { setBusy(false); } };
  const field = (key, label, props = {}) => <div><label className="label">{label}</label><input className="field" value={values[key]} onChange={(e) => setValues({ ...values, [key]: e.target.value })} {...props} /></div>;
  return <Modal title={isEditing ? 'Edit asset record' : 'Add a new asset'} onClose={onClose} wide><form onSubmit={submit}><div className="grid gap-4 sm:grid-cols-2 lg:grid-cols-3">{field('assetTag', 'Asset tag', { placeholder: 'AST-IT-009', disabled: isEditing })}{field('name', 'Asset name', { placeholder: 'e.g. Lenovo ThinkPad X1' })}<div><label className="label">Category</label><select className="field" value={values.category} onChange={(e) => setValues({ ...values, category: e.target.value })}>{['Laptop', 'Projector', 'Laboratory Equipment', 'Networking', 'Camera', 'Printer', 'Furniture', 'Other'].map((item) => <option key={item}>{item}</option>)}</select></div>{field('manufacturer', 'Manufacturer', { placeholder: 'Apple, Dell, Epson…' })}{field('model', 'Model', { placeholder: 'Model number' })}{field('serialNumber', 'Serial number', { placeholder: 'Device serial' })}{field('location', 'Current location', { placeholder: 'e.g. Innovation Lab' })}{field('department', 'Department') }<div><label className="label">Condition</label><select className="field" value={values.condition} onChange={(e) => setValues({ ...values, condition: e.target.value })}>{['excellent', 'good', 'fair', 'poor'].map((item) => <option key={item} value={item}>{titleCase(item)}</option>)}</select></div>{isEditing && <div><label className="label">Operational status</label><select className="field" value={values.status} onChange={(e) => setValues({ ...values, status: e.target.value })}>{['available', 'maintenance', 'retired', 'lost'].map((item) => <option key={item} value={item}>{titleCase(item)}</option>)}</select></div>}{field('purchaseDate', 'Purchase date', { type: 'date' })}{field('purchaseCost', 'Purchase cost (₹)', { type: 'number', min: '0', step: '1', placeholder: '0' })}{field('warrantyExpiry', 'Warranty expiry', { type: 'date' })}{field('maintenanceIntervalDays', 'Service interval (days)', { type: 'number', min: '1' })}{field('lastMaintenanceDate', 'Last service date', { type: 'date' })}<div className="sm:col-span-2 lg:col-span-3"><label className="label">Operational notes</label><textarea className="field min-h-24 resize-y" value={values.notes} onChange={(e) => setValues({ ...values, notes: e.target.value })} placeholder="Condition, accessories, usage context, or other details…" /></div></div>{error && <p className="mt-4 rounded-xl bg-rose-50 px-3 py-2 text-sm font-semibold text-rose-600">{error}</p>}<div className="mt-6 flex justify-end gap-3"><button type="button" onClick={onClose} className="btn-secondary">Cancel</button><button disabled={busy} className="btn-primary">{busy ? 'Saving…' : isEditing ? 'Save changes' : 'Create asset'} <Check size={16} /></button></div></form></Modal>;
}
function CheckoutForm({ token, asset, onClose, onDone }) {
  const [values, setValues] = useState({ assigneeName: '', assigneeEmail: '', assigneeDepartment: '', dueDate: isoInput(new Date(Date.now() + 7 * 86400000)), conditionOut: asset.condition, checkoutNotes: '' }); const [busy, setBusy] = useState(false); const [error, setError] = useState('');
  const submit = async (event) => { event.preventDefault(); setBusy(true); try { await api.checkout(token, idOf(asset), values); onDone(); } catch (err) { setError(err.message); } finally { setBusy(false); } };
  return <Modal title={`Check out ${asset.assetTag}`} onClose={onClose}><form onSubmit={submit} className="space-y-4"><p className="rounded-xl bg-brand-50 p-3 text-xs font-semibold leading-5 text-brand-700">This creates a custody record and moves the asset to <strong>Assigned</strong>.</p><FormInput label="Borrower name" value={values.assigneeName} onChange={(value) => setValues({ ...values, assigneeName: value })} required placeholder="Full name" /><FormInput label="Borrower email" type="email" value={values.assigneeEmail} onChange={(value) => setValues({ ...values, assigneeEmail: value })} placeholder="name@nexus.edu" /><FormInput label="Department or club" value={values.assigneeDepartment} onChange={(value) => setValues({ ...values, assigneeDepartment: value })} placeholder="Robotics Club" /><FormInput label="Due date" type="date" value={values.dueDate} onChange={(value) => setValues({ ...values, dueDate: value })} required /><div><label className="label">Condition at handoff</label><select className="field" value={values.conditionOut} onChange={(e) => setValues({ ...values, conditionOut: e.target.value })}>{['excellent', 'good', 'fair', 'poor'].map((item) => <option key={item}>{titleCase(item)}</option>)}</select></div><div><label className="label">Handoff notes</label><textarea className="field min-h-20" value={values.checkoutNotes} onChange={(e) => setValues({ ...values, checkoutNotes: e.target.value })} placeholder="Accessories, context, or acknowledgement…" /></div>{error && <p className="text-sm font-bold text-rose-600">{error}</p>}<FormActions busy={busy} label="Confirm checkout" onClose={onClose} /></form></Modal>;
}
function ReturnForm({ token, assignment, onClose, onDone }) { const [conditionIn, setCondition] = useState('good'); const [returnNotes, setNotes] = useState(''); const [busy, setBusy] = useState(false); const [error, setError] = useState(''); const submit = async (event) => { event.preventDefault(); setBusy(true); try { await api.returnAsset(token, idOf(assignment), { conditionIn, returnNotes }); onDone(); } catch (err) { setError(err.message); } finally { setBusy(false); } }; return <Modal title="Return asset" onClose={onClose}><form onSubmit={submit} className="space-y-4"><p className="rounded-xl bg-blue-50 p-3 text-xs font-semibold text-blue-700">Returned items in poor condition are automatically moved to maintenance.</p><div><label className="label">Condition on return</label><select className="field" value={conditionIn} onChange={(e) => setCondition(e.target.value)}>{['excellent', 'good', 'fair', 'poor'].map((item) => <option key={item}>{titleCase(item)}</option>)}</select></div><div><label className="label">Return notes</label><textarea className="field min-h-24" value={returnNotes} onChange={(e) => setNotes(e.target.value)} placeholder="Damage, missing accessories, or observations…" /></div>{error && <p className="text-sm font-bold text-rose-600">{error}</p>}<FormActions busy={busy} label="Confirm return" onClose={onClose} /></form></Modal>; }
function MaintenanceForm({ token, asset, onClose, onDone }) { const [values, setValues] = useState({ title: '', type: 'preventive', priority: 'medium', dueDate: isoInput(new Date(Date.now() + 7 * 86400000)), notes: '' }); const [busy, setBusy] = useState(false); const [error, setError] = useState(''); const submit = async (event) => { event.preventDefault(); setBusy(true); try { await api.createMaintenance(token, { ...values, assetId: idOf(asset) }); onDone(); } catch (err) { setError(err.message); } finally { setBusy(false); } }; return <Modal title="Open maintenance ticket" onClose={onClose}><form onSubmit={submit} className="space-y-4"><p className="rounded-xl bg-amber-50 p-3 text-xs font-semibold text-amber-700">The asset becomes unavailable while maintenance is open unless it is currently assigned.</p><FormInput label="Issue or service title" value={values.title} onChange={(value) => setValues({ ...values, title: value })} required placeholder="e.g. Annual calibration" /><div className="grid grid-cols-2 gap-3"><div><label className="label">Work type</label><select className="field" value={values.type} onChange={(e) => setValues({ ...values, type: e.target.value })}>{['preventive', 'repair', 'inspection', 'calibration'].map((item) => <option key={item}>{titleCase(item)}</option>)}</select></div><div><label className="label">Priority</label><select className="field" value={values.priority} onChange={(e) => setValues({ ...values, priority: e.target.value })}>{['low', 'medium', 'high', 'critical'].map((item) => <option key={item}>{titleCase(item)}</option>)}</select></div></div><FormInput label="Due date" type="date" value={values.dueDate} onChange={(value) => setValues({ ...values, dueDate: value })} required /><div><label className="label">Work notes</label><textarea className="field min-h-24" value={values.notes} onChange={(e) => setValues({ ...values, notes: e.target.value })} placeholder="Symptoms, service scope, or inspection checklist…" /></div>{error && <p className="text-sm font-bold text-rose-600">{error}</p>}<FormActions busy={busy} label="Create ticket" onClose={onClose} /></form></Modal>; }
function FormInput({ label, value, onChange, ...props }) { return <div><label className="label">{label}</label><input className="field" value={value} onChange={(e) => onChange(e.target.value)} {...props} /></div>; }
function FormActions({ busy, label, onClose }) { return <div className="flex justify-end gap-3 pt-2"><button type="button" onClick={onClose} className="btn-secondary">Cancel</button><button disabled={busy} className="btn-primary">{busy ? 'Saving…' : label}<Check size={16} /></button></div>; }
function printLabel(asset) { const pop = window.open('', '_blank', 'width=420,height=520'); if (!pop) return; pop.document.write(`<html><head><title>${asset.assetTag}</title><style>body{font-family:Arial;padding:34px;text-align:center;color:#111827}.tag{font-size:20px;font-weight:800}.name{font-size:15px;color:#475569;margin:8px}.qr{margin:22px auto;width:150px;height:150px}small{color:#64748b}</style></head><body><div class="tag">NEXUS ASSETS</div><div class="name">${asset.name}</div><canvas class="qr" id="qr"></canvas><small>${asset.assetTag} · ${asset.location}</small><script src="https://cdn.jsdelivr.net/npm/qrcode@1.5.4/build/qrcode.min.js"><\/script><script>QRCode.toCanvas(document.getElementById('qr'),'${asset.qrCode}',{width:150},()=>window.print())<\/script></body></html>`); pop.document.close(); }

function Scanner({ token, user, show }) {
  const scanner = useRef(null); const [cameraOn, setCameraOn] = useState(false); const [manual, setManual] = useState(''); const [found, setFound] = useState(null); const [loading, setLoading] = useState(false); const [error, setError] = useState(''); const [checkout, setCheckout] = useState(false);
  const stop = async () => { if (scanner.current) { try { if (scanner.current.isScanning) await scanner.current.stop(); } catch { /* reader has already stopped */ } scanner.current.clear?.(); scanner.current = null; } setCameraOn(false); };
  useEffect(() => () => { stop(); }, []); // eslint-disable-line react-hooks/exhaustive-deps
  const lookup = async (code) => { if (!code) return; setLoading(true); setError(''); try { await stop(); const result = await api.lookup(token, code.trim()); const detail = await api.asset(token, idOf(result.asset)); setFound(detail); show(`Asset found: ${result.asset.assetTag}`); } catch (err) { setFound(null); setError(err.message); } finally { setLoading(false); } };
  const start = async () => { setError(''); setFound(null); try { const reader = new Html5Qrcode('nexus-qr-reader'); scanner.current = reader; await reader.start({ facingMode: 'environment' }, { fps: 10, qrbox: { width: 220, height: 220 }, aspectRatio: 1 }, (decodedText) => lookup(decodedText), () => {}); setCameraOn(true); } catch (err) { scanner.current = null; setError('Camera access was unavailable. Enter the asset tag manually instead.'); } };
  const canCheckout = ['admin', 'asset_manager'].includes(user.role);
  return <div className="mx-auto max-w-5xl space-y-5"><section className="overflow-hidden rounded-3xl bg-[#10163a] p-6 text-white shadow-card sm:p-9"><div className="grid gap-8 md:grid-cols-[1fr_.9fr] md:items-center"><div><p className="eyebrow text-indigo-200">QR-powered custody</p><h2 className="mt-2 text-3xl font-extrabold tracking-tight">Know where every asset is—<span className="text-indigo-300">instantly.</span></h2><p className="mt-4 max-w-md text-sm leading-6 text-indigo-100">Scan a Nexus label at checkout, return, transfer, or inspection. Every action stays tied to a verifiable lifecycle record.</p><div className="mt-6 flex flex-wrap gap-3"><button onClick={cameraOn ? stop : start} className="btn bg-white text-brand-700 hover:bg-indigo-50">{cameraOn ? <><X size={17} />Stop camera</> : <><ScanLine size={17} />Start camera scan</>}</button><span className="inline-flex items-center gap-2 px-2 text-xs font-bold text-indigo-200"><ShieldCheck size={15} />Audit trail enabled</span></div></div><div className="relative mx-auto w-full max-w-sm"><div className="absolute -inset-3 rounded-[2rem] bg-brand-500/20 blur-2xl" /><div className="relative overflow-hidden rounded-3xl border border-white/15 bg-slate-950 p-3"><div id="nexus-qr-reader" className="qr-reader min-h-64 overflow-hidden rounded-2xl bg-slate-900" />{!cameraOn && <div className="absolute inset-3 grid place-items-center rounded-2xl border border-dashed border-indigo-300/25 text-center"><div><QrCode size={40} className="mx-auto text-indigo-300" /><p className="mt-3 text-xs font-bold text-indigo-100">Camera preview appears here</p></div></div>}</div></div></div></section><section className="surface p-5 sm:p-6"><div className="grid gap-5 md:grid-cols-[1fr_auto]"><div><p className="eyebrow">Manual lookup</p><h3 className="mt-1 font-extrabold text-ink">No camera? Enter an asset tag.</h3><form onSubmit={(event) => { event.preventDefault(); lookup(manual); }} className="mt-4 flex max-w-xl gap-2"><input className="field font-mono" value={manual} onChange={(e) => setManual(e.target.value)} placeholder="AST-IT-001 or encoded QR value" /><button disabled={loading} className="btn-primary">{loading ? 'Looking up…' : 'Find asset'}</button></form>{error && <p className="mt-3 text-xs font-bold text-rose-600">{error}</p>}</div><div className="rounded-2xl bg-slate-50 p-4 text-xs text-slate-500"><p className="font-extrabold text-ink">Try the demo</p><p className="mt-1 leading-5">Scan or enter <span className="font-mono font-bold text-brand-600">AST-IT-001</span> to open an overdue laptop loan.</p></div></div></section>{found && <section className="surface overflow-hidden"><div className="flex flex-col gap-5 p-5 sm:flex-row sm:items-center sm:p-6"><AssetGlyph category={found.asset.category} size="large" /><div className="min-w-0 flex-1"><div className="flex flex-wrap items-center gap-2"><h3 className="text-xl font-extrabold text-ink">{found.asset.name}</h3><Badge value={found.asset.status} /></div><p className="mt-1 font-mono text-xs text-slate-400">{found.asset.assetTag} · {found.asset.location}</p>{found.activeAssignment ? <p className="mt-3 text-sm font-bold text-amber-700">Assigned to {found.activeAssignment.assigneeName} · {relative(found.activeAssignment.dueDate)}</p> : <p className="mt-3 text-sm font-bold text-emerald-700">Ready for assignment</p>}</div>{canCheckout && found.asset.status === 'available' && <button onClick={() => setCheckout(true)} className="btn-primary"><ArrowRightLeft size={16} />Check out</button>}{canCheckout && found.activeAssignment && <button onClick={() => setCheckout('return')} className="btn-secondary"><PackageCheck size={16} />Return</button>}</div>{checkout === true && <CheckoutForm token={token} asset={found.asset} onClose={() => setCheckout(false)} onDone={() => { setCheckout(false); lookup(found.asset.assetTag); show('Checkout completed from QR scan.'); }} />}{checkout === 'return' && <ReturnForm token={token} assignment={found.activeAssignment} onClose={() => setCheckout(false)} onDone={() => { setCheckout(false); lookup(found.asset.assetTag); show('Return completed from QR scan.'); }} />}</section>}</div>;
}

function MaintenancePage({ token, user, show }) {
  const [tickets, setTickets] = useState(null); const [status, setStatus] = useState(''); const [active, setActive] = useState(null); const [error, setError] = useState('');
  const canManage = ['admin', 'asset_manager', 'technician'].includes(user.role); const load = async () => { try { setError(''); setTickets((await api.maintenance(token, status)).tickets); } catch (err) { setError(err.message); } };
  useEffect(() => { load(); }, [token, status]); // eslint-disable-line react-hooks/exhaustive-deps
  if (error) return <ConnectionError error={error} onRetry={load} />;
  return <div className="space-y-5"><section className="surface overflow-hidden"><div className="flex flex-col gap-4 border-b p-5 sm:flex-row sm:items-center sm:justify-between sm:p-6"><div><p className="eyebrow">Technician workspace</p><h2 className="mt-1 text-xl font-extrabold text-ink">Keep campus operations moving</h2></div><div className="flex rounded-xl bg-slate-100 p-1">{[['', 'All'], ['open', 'Open'], ['in_progress', 'In progress'], ['resolved', 'Resolved']].map(([value, label]) => <button key={label} onClick={() => setStatus(value)} className={`rounded-lg px-3 py-2 text-xs font-extrabold transition ${status === value ? 'bg-white text-brand-700 shadow-sm' : 'text-slate-500'}`}>{label}</button>)}</div></div>{!tickets ? <Spinner /> : tickets.length === 0 ? <Empty icon={Wrench} title="No maintenance tickets" copy="Asset maintenance tickets created from the registry appear here." /> : <div className="divide-y">{tickets.map((ticket) => <button onClick={() => setActive(ticket)} key={idOf(ticket)} className="flex w-full flex-col gap-3 p-5 text-left transition hover:bg-slate-50 sm:flex-row sm:items-center sm:px-6"><div className={`grid h-10 w-10 shrink-0 place-items-center rounded-xl ${ticket.priority === 'critical' || ticket.priority === 'high' ? 'bg-rose-50 text-rose-600' : 'bg-amber-50 text-amber-600'}`}><Wrench size={18} /></div><div className="min-w-0 flex-1"><div className="flex flex-wrap items-center gap-2"><p className="font-extrabold text-ink">{ticket.title}</p><Badge value={ticket.status} /></div><p className="mt-1 truncate text-xs text-slate-500"><span className="font-mono">{ticket.asset?.assetTag}</span> · {ticket.asset?.name} · {ticket.asset?.location}</p></div><div className="flex items-center gap-4"><div className="text-right"><p className={`text-xs font-extrabold ${new Date(ticket.dueDate) < new Date() ? 'text-rose-600' : 'text-slate-700'}`}>{relative(ticket.dueDate)}</p><p className="mt-0.5 text-[10px] font-bold text-slate-400">{titleCase(ticket.priority)} priority</p></div><ChevronRight size={17} className="text-slate-300" /></div></button>)}</div>}</section>{active && <TicketDetail ticket={active} canManage={canManage} token={token} onClose={() => setActive(null)} onChanged={() => { setActive(null); load(); show('Maintenance ticket updated and audit recorded.'); }} />}</div>;
}
function TicketDetail({ ticket, canManage, token, onClose, onChanged }) { const [mode, setMode] = useState(null); return <Modal title="Maintenance ticket" onClose={onClose}><div className="flex items-start gap-3"><div className="rounded-xl bg-amber-50 p-3 text-amber-600"><Wrench size={20} /></div><div className="min-w-0"><div className="flex flex-wrap gap-2"><h3 className="font-extrabold text-ink">{ticket.title}</h3><Badge value={ticket.status} /></div><p className="mt-1 text-xs text-slate-500"><span className="font-mono">{ticket.asset?.assetTag}</span> · due {date(ticket.dueDate)}</p></div></div><div className="mt-5 grid grid-cols-2 gap-3"><InfoCard label="Work type" value={titleCase(ticket.type)} icon={Wrench} /><InfoCard label="Priority" value={titleCase(ticket.priority)} icon={AlertTriangle} /><InfoCard label="Assigned to" value={ticket.assignedTo?.name || 'Unassigned'} icon={Users} /><InfoCard label="Cost" value={ticket.cost ? `₹${Number(ticket.cost).toLocaleString('en-IN')}` : 'Not recorded'} icon={FileText} /></div><div className="mt-5 rounded-2xl bg-slate-50 p-4"><p className="eyebrow">Work notes</p><p className="mt-2 text-sm leading-6 text-slate-600">{ticket.notes || 'No work notes provided.'}</p>{ticket.resolutionNotes && <><p className="mt-4 eyebrow">Resolution</p><p className="mt-2 text-sm leading-6 text-slate-600">{ticket.resolutionNotes}</p></>}</div>{canManage && ticket.status !== 'resolved' && <button onClick={() => setMode('resolve')} className="btn-primary mt-6 w-full"><CheckCircle2 size={16} />{ticket.status === 'open' ? 'Start or resolve work' : 'Resolve maintenance'}</button>}{mode && <TicketUpdateForm ticket={ticket} token={token} onClose={() => setMode(null)} onDone={onChanged} />}</Modal>; }
function TicketUpdateForm({ ticket, token, onClose, onDone }) { const [status, setStatus] = useState(ticket.status === 'open' ? 'in_progress' : 'resolved'); const [cost, setCost] = useState(ticket.cost || ''); const [resolutionNotes, setNotes] = useState(''); const [busy, setBusy] = useState(false); const [error, setError] = useState(''); const submit = async (event) => { event.preventDefault(); setBusy(true); try { await api.updateMaintenance(token, idOf(ticket), { status, cost: cost === '' ? undefined : Number(cost), resolutionNotes }); onDone(); } catch (err) { setError(err.message); } finally { setBusy(false); } }; return <Modal title="Update maintenance" onClose={onClose}><form onSubmit={submit} className="space-y-4"><div><label className="label">Status</label><select className="field" value={status} onChange={(e) => setStatus(e.target.value)}><option value="in_progress">In progress</option><option value="resolved">Resolved</option></select></div><FormInput label="Service cost (₹)" type="number" min="0" value={cost} onChange={setCost} placeholder="Optional" /><div><label className="label">Technician resolution notes</label><textarea className="field min-h-28" value={resolutionNotes} onChange={(e) => setNotes(e.target.value)} placeholder="Parts replaced, work completed, or follow-up needed…" /></div>{error && <p className="text-sm font-bold text-rose-600">{error}</p>}<FormActions busy={busy} label="Save maintenance update" onClose={onClose} /></form></Modal>; }

function Reports({ token, show }) {
  const [loading, setLoading] = useState(''); const reports = [
    { type: 'inventory', title: 'Inventory register', copy: 'Complete asset register with identity, condition, location, and operational status.', icon: Box, colour: 'bg-brand-50 text-brand-600' },
    { type: 'maintenance', title: 'Maintenance summary', copy: 'Open, in-progress, and completed service work with due dates and cost traceability.', icon: Wrench, colour: 'bg-amber-50 text-amber-600' },
    { type: 'audit', title: 'Audit activity log', copy: 'Timestamped accountability record for asset, assignment, and maintenance actions.', icon: ClipboardCheck, colour: 'bg-emerald-50 text-emerald-600' },
  ];
  const download = async (type) => { setLoading(type); try { const report = await api.report(token, type); generatePdf(type, report); show(`${report.title} downloaded as a PDF.`); } catch (err) { show(err.message, 'error'); } finally { setLoading(''); } };
  return <div className="mx-auto max-w-5xl space-y-5"><section className="overflow-hidden rounded-3xl bg-gradient-to-br from-brand-700 to-[#252c76] p-7 text-white shadow-card sm:p-9"><div className="max-w-2xl"><p className="eyebrow text-indigo-200">Audit-ready exports</p><h2 className="mt-2 text-3xl font-extrabold tracking-tight">Clear records. <span className="text-indigo-200">Confident decisions.</span></h2><p className="mt-4 text-sm leading-6 text-indigo-100">Generate a polished PDF directly from your current Nexus data. Every report includes a generation timestamp and operational totals.</p></div><div className="mt-7 flex flex-wrap gap-3 text-xs font-bold text-indigo-100"><span className="rounded-full border border-white/15 px-3 py-1.5">Organization branded</span><span className="rounded-full border border-white/15 px-3 py-1.5">Timestamped</span><span className="rounded-full border border-white/15 px-3 py-1.5">Share-ready PDFs</span></div></section><section className="grid gap-4 md:grid-cols-3">{reports.map((report) => <article className="surface flex flex-col p-5" key={report.type}><div className={`grid h-11 w-11 place-items-center rounded-xl ${report.colour}`}><report.icon size={21} /></div><h3 className="mt-5 font-extrabold text-ink">{report.title}</h3><p className="mt-2 flex-1 text-sm leading-6 text-slate-500">{report.copy}</p><button disabled={Boolean(loading)} onClick={() => download(report.type)} className="btn-secondary mt-6 w-full">{loading === report.type ? 'Preparing PDF…' : <><ArrowDownToLine size={16} />Download PDF</>}</button></article>)}</section><section className="surface p-5 sm:p-6"><div className="flex gap-3"><div className="rounded-xl bg-slate-100 p-2.5 text-slate-600"><QrCode size={18} /></div><div><h3 className="font-extrabold text-ink">Need a label for a single item?</h3><p className="mt-1 text-sm leading-6 text-slate-500">Open any asset from the registry and use <strong>Print QR label</strong> to create a compact, scan-ready label for physical equipment.</p></div></div></section></div>;
}
function generatePdf(type, report) {
  const doc = new jsPDF({ unit: 'pt', format: 'a4' }); const generated = new Date(report.generatedAt).toLocaleString();
  doc.setFillColor(70, 82, 223); doc.rect(0, 0, 595, 75, 'F'); doc.setTextColor(255, 255, 255); doc.setFont('helvetica', 'bold'); doc.setFontSize(17); doc.text('NEXUS ASSETS', 42, 34); doc.setFontSize(9); doc.setFont('helvetica', 'normal'); doc.text('University Operations · Smart Asset Intelligence', 42, 51);
  doc.setTextColor(17, 24, 39); doc.setFont('helvetica', 'bold'); doc.setFontSize(18); doc.text(report.title, 42, 110); doc.setFont('helvetica', 'normal'); doc.setTextColor(100, 116, 139); doc.setFontSize(9); doc.text(`Generated ${generated}`, 42, 128);
  const totals = Object.entries(report.totals || {}).map(([key, value]) => `${titleCase(key)}: ${typeof value === 'number' && key.toLowerCase().includes('cost') ? `₹${value.toLocaleString('en-IN')}` : value}`).join('   •   '); doc.setTextColor(70, 82, 223); doc.setFont('helvetica', 'bold'); doc.text(totals, 42, 151);
  let head; let body;
  if (type === 'inventory') { head = ['Asset tag', 'Asset', 'Category', 'Location', 'Condition', 'Status']; body = report.rows.map((row) => [row.assetTag, row.name, row.category, row.location, titleCase(row.condition), titleCase(row.status)]); }
  else if (type === 'maintenance') { head = ['Asset', 'Ticket', 'Type', 'Priority', 'Due date', 'Status', 'Cost']; body = report.rows.map((row) => [row.asset?.assetTag || '—', row.title, titleCase(row.type), titleCase(row.priority), date(row.dueDate), titleCase(row.status), row.cost ? `₹${row.cost.toLocaleString('en-IN')}` : '—']); }
  else { head = ['Time', 'Action', 'Entity', 'Performed by', 'Details']; body = report.rows.map((row) => [new Date(row.createdAt).toLocaleString(), titleCase(row.action), titleCase(row.entityType), row.actor?.name || row.actorName || 'System', Object.entries(row.details || {}).map(([key, value]) => `${key}: ${value}`).join(', ').slice(0, 80)]); }
  autoTable(doc, { startY: 171, head: [head], body, theme: 'striped', styles: { font: 'helvetica', fontSize: 7.4, cellPadding: 5, textColor: [51, 65, 85] }, headStyles: { fillColor: [31, 41, 86], textColor: [255, 255, 255], fontStyle: 'bold' }, alternateRowStyles: { fillColor: [248, 250, 252] }, margin: { left: 42, right: 42 }, didDrawPage: (hook) => { doc.setFontSize(7); doc.setTextColor(148, 163, 184); doc.text(`Nexus Assets · Confidential operational record · Page ${hook.pageNumber}`, 42, 810); } });
  doc.save(`${type}-report-${new Date().toISOString().slice(0, 10)}.pdf`);
}

export default App;
